// 사건번호에서 죄명(사건명) 분리
function splitCaseNumber(cn) {
  if (!cn) return { number: "", name: "" };
  const re = new RegExp(
    "^\\s*(\\d{4}\\s*(?:" + CASE_SUFFIX + ")\\s*제?\\s*\\d+)\\s*(.*)$"
  );
  const m = cn.match(re);
  if (m) return { number: m[1].replace(/\s+/g, ""), name: (m[2] || "").trim() };
  return { number: cn, name: "" };
}

// 저장된 옛 데이터 보강 + 사건명 자동 분리(최초 1회)
function migrateCase(c) {
  const out = { ...c };
  if (out.caseName === undefined) {
    const { number, name } = splitCaseNumber(out.caseNumber || "");
    out.caseNumber = number;
    out.caseName = name;
  }
  if (out.claimed === undefined) out.claimed = false;
  if (!out.feeForm) out.feeForm = defaultFeeForm();
  if (out.verdictDate === undefined) out.verdictDate = "";
  if (out.depositDate === undefined) out.depositDate = "";
  if (out.depositAmount === undefined) out.depositAmount = "";
  if (out.appeal === undefined) out.appeal = "";
  if (out.appealStamped === undefined) out.appealStamped = false;
  return out;
}

