// 암호화 (AES-GCM + PBKDF2)
const _tenc = new TextEncoder();
const _tdec = new TextDecoder();
function _b64(buf) {
  const b = new Uint8Array(buf);
  let s = "";
  for (let i = 0; i < b.length; i++) s += String.fromCharCode(b[i]);
  return btoa(s);
}
function _unb64(s) {
  const bin = atob(s);
  const u = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) u[i] = bin.charCodeAt(i);
  return u;
}
async function _deriveKey(pass, salt) {
  const base = await crypto.subtle.importKey("raw", _tenc.encode(pass), "PBKDF2", false, [
    "deriveKey",
  ]);
  return crypto.subtle.deriveKey(
    { name: "PBKDF2", salt, iterations: 150000, hash: "SHA-256" },
    base,
    { name: "AES-GCM", length: 256 },
    false,
    ["encrypt", "decrypt"]
  );
}
async function encryptData(obj, pass) {
  const salt = crypto.getRandomValues(new Uint8Array(16));
  const iv = crypto.getRandomValues(new Uint8Array(12));
  const key = await _deriveKey(pass, salt);
  const ct = await crypto.subtle.encrypt(
    { name: "AES-GCM", iv },
    key,
    _tenc.encode(JSON.stringify(obj))
  );
  return { enc: true, salt: _b64(salt), iv: _b64(iv), ct: _b64(ct) };
}
async function decryptData(blob, pass) {
  const key = await _deriveKey(pass, _unb64(blob.salt));
  const pt = await crypto.subtle.decrypt(
    { name: "AES-GCM", iv: _unb64(blob.iv) },
    key,
    _unb64(blob.ct)
  );
  return JSON.parse(_tdec.decode(pt));
}

// JSONBin API
async function jbCreate(masterKey, payload) {
  const r = await fetch(JB_BASE, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "X-Master-Key": masterKey,
      "X-Bin-Private": "true",
      "X-Bin-Name": "gukseon-cases",
    },
    body: JSON.stringify(payload),
  });
  if (!r.ok) throw new Error("클라우드 저장소 생성 실패 (" + r.status + ")");
  const j = await r.json();
  return (j.metadata && j.metadata.id) || j.id;
}
async function jbRead(masterKey, binId) {
  const r = await fetch(JB_BASE + "/" + binId + "/latest", {
    headers: { "X-Master-Key": masterKey, "X-Bin-Meta": "false" },
  });
  if (r.status === 404) return null;
  if (!r.ok) throw new Error("불러오기 실패 (" + r.status + ")");
  return r.json();
}
async function jbUpdate(masterKey, binId, payload) {
  const r = await fetch(JB_BASE + "/" + binId, {
    method: "PUT",
    headers: { "Content-Type": "application/json", "X-Master-Key": masterKey },
    body: JSON.stringify(payload),
  });
  if (!r.ok) throw new Error("동기화 실패 (" + r.status + ")");
  return r.json();
}

function formatSyncTime(ms) {
  if (!ms) return "";
  try {
    return new Date(ms).toLocaleString("ko-KR", {
      month: "numeric",
      day: "numeric",
      hour: "2-digit",
      minute: "2-digit",
    });
  } catch (e) {
    return "";
  }
}

// ───────────── 공소장 PDF 읽기 (PDF.js + OCR) ─────────────
const PDFJS_URL = "https://cdn.jsdelivr.net/npm/pdfjs-dist@3.11.174/build/pdf.min.js";
const PDFJS_WORKER = "https://cdn.jsdelivr.net/npm/pdfjs-dist@3.11.174/build/pdf.worker.min.js";
const TESSERACT_URL = "https://cdn.jsdelivr.net/npm/tesseract.js@5/dist/tesseract.min.js";

function loadScript(src) {
  return new Promise((resolve, reject) => {
    if (Array.from(document.scripts).some((s) => s.src === src)) return resolve();
    const el = document.createElement("script");
    el.src = src;
    el.onload = () => resolve();
    el.onerror = () => reject(new Error("필요한 구성요소를 불러오지 못했습니다. 인터넷 연결을 확인해 주세요."));
    document.head.appendChild(el);
  });
}

let _pdfjs = null;
async function getPdfjs() {
  if (_pdfjs) return _pdfjs;
  await loadScript(PDFJS_URL);
  const lib = window.pdfjsLib;
  if (!lib) throw new Error("PDF 구성요소 로드 실패");
  lib.GlobalWorkerOptions.workerSrc = PDFJS_WORKER;
  _pdfjs = lib;
  return lib;
}
async function getTesseract() {
  if (window.Tesseract) return window.Tesseract;
  await loadScript(TESSERACT_URL);
  if (!window.Tesseract) throw new Error("OCR 구성요소 로드 실패");
  return window.Tesseract;
}

