async function extractChargeSheetText(file, onProgress) {
  const pdfjs = await getPdfjs();
  const buf = await file.arrayBuffer();
  const pdf = await pdfjs.getDocument({ data: new Uint8Array(buf) }).promise;
  const pages = Math.min(pdf.numPages, 3);
  let text = "";
  for (let i = 1; i <= pages; i++) {
    const page = await pdf.getPage(i);
    const tc = await page.getTextContent();
    text += tc.items.map((it) => it.str).join(" ") + "\n";
  }
  // 글자가 거의 없으면 스캔 문서로 보고 OCR
  if (text.replace(/\s/g, "").length < 40) {
    if (onProgress) onProgress("스캔 문서로 보입니다. 글자 인식(OCR) 준비 중…");
    const T = await getTesseract();
    let ocr = "";
    const ocrPages = Math.min(pdf.numPages, 2);
    for (let i = 1; i <= ocrPages; i++) {
      const page = await pdf.getPage(i);
      const viewport = page.getViewport({ scale: 3 });
      const canvas = document.createElement("canvas");
      canvas.width = viewport.width;
      canvas.height = viewport.height;
      await page.render({ canvasContext: canvas.getContext("2d"), viewport }).promise;
      const { data } = await T.recognize(canvas, "kor", {
        logger: (m) => {
          if (m.status === "recognizing text" && onProgress)
            onProgress("글자 인식 중… " + Math.round((m.progress || 0) * 100) + "%");
        },
      });
      ocr += (data.text || "") + "\n";
    }
    text = ocr;
  }
  return text;
}

// 죄명 축약: 쉼표로 여러 개면 첫 죄명 + ' 등' (및·· 등 다른 기호는 그대로 표기)
function condenseCharge(s) {
  if (!s) return "";
  const parts = s.trim().split(/[,，]/).map((x) => x.trim()).filter(Boolean);
  if (parts.length > 1) return parts[0] + " 등";
  return parts[0] || "";
}

// 공소장 텍스트에서 항목 추출
function parseChargeSheet(raw) {
  const flat = (raw || "").replace(/\r/g, " ").replace(/[ \t]+/g, " ");
  const out = { caseNumber: "", caseName: "", defendant: "", contact: "", multiDefendant: false };

  // 피고인: 이름 바로 뒤 (주민번호) 패턴 우선
  let m = flat.match(/([가-힣]{2,5})\s*\(\s*\d{6}\s*[-–]\s*[\d*]{1,7}/);
  if (m) out.defendant = m[1];
  else {
    m = flat.match(/피\s*고\s*인[\s:.\d)）]*([가-힣]{2,5})/);
    if (m && !/관련|사항|성명|인적|별지|불상|기재|위와|같이/.test(m[1]))
      out.defendant = m[1];
  }

  // 사건명 ①: 본문 죄명 줄
  m = flat.match(
    /죄\s*명\s*[:：]?\s*([가-힣A-Za-z0-9·()\s,]{1,60}?)\s*(?:적용|공소\s*사실|구속|변\s*호|주\s*문|검\s*사|$)/
  );
  if (m) out.caseName = condenseCharge(m[1].trim().replace(/\s{2,}/g, " ").slice(0, 60));
  // 사건명 ②: 죄명 줄 실패 시, 상단 접수 도장(사건번호 사건명 8자리날짜)
  if (!out.caseName) {
    const s = flat.match(
      /(?:고단|고합|고정|고약|구단|구합|가단|가합|노|초[가-힣]?)\s*\d+\s+([가-힣][가-힣\s·]*?)\s+\d{8}\b/
    );
    if (s) out.caseName = condenseCharge(s[1].trim().replace(/\s{2,}/g, " "));
  }

  m = flat.match(
    /(\d{4}\s*(?:형제|고단|고합|고정|고약|구합|구단|가단|가합|노|초[가-힣]?)\s*제?\s*\d+)/
  );
  if (m) out.caseNumber = m[1].replace(/\s+/g, "");

  m = flat.match(/01[016789][\-\s]?\d{3,4}[\-\s]?\d{4}/);
  if (m) out.contact = m[0].replace(/\s/g, "");

  out.multiDefendant = (flat.match(/\d{6}\s*[-–]\s*[\d*]{1,7}/g) || []).length > 1;

  return out;
}

// 파일명에서 추출 (형식: 이름_사건번호_사건명_공소장_날짜)
function parseFilename(name) {
  const base = (name || "").replace(/\.[^.]+$/, "");
  const parts = base.split(/[_\s]+/).filter(Boolean);
  const out = { defendant: "", caseNumber: "", caseName: "" };
  const cnRe = /^(\d{2,4})(고단|고합|고정|고약|도|노|구합|구단|가단|가합|차|초[가-힣]?|형제)(\d+)$/;
  const idx = parts.findIndex((p) => cnRe.test(p));
  if (idx >= 0) {
    const mm = parts[idx].match(cnRe);
    let yr = mm[1];
    if (yr.length === 2) yr = "20" + yr;
    out.caseNumber = yr + mm[2] + mm[3];
    out.defendant = parts.slice(0, idx).join(" ").trim();
    const rest = [];
    for (let i = idx + 1; i < parts.length; i++) {
      if (/공소장|공판|약식|불기소|결정|사건/.test(parts[i]) || /^\d{1,4}$/.test(parts[i]))
        break;
      rest.push(parts[i]);
    }
    out.caseName = rest.join(" ").trim();
  } else if (parts.length) {
    out.defendant = parts[0];
  }
  return out;
}

// 날짜 표기: 2026-06-11 → "6. 11."
function formatDate(iso) {
  if (!iso) return "";
  const parts = iso.split("-");
  if (parts.length !== 3) return iso;
  return `${Number(parts[1])}. ${Number(parts[2])}.`;
}

// 기일까지 남은 일수 (오늘 기준)
function daysUntil(iso) {
  if (!iso) return null;
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  const d = new Date(iso + "T00:00:00");
  if (isNaN(d.getTime())) return null;
  return Math.round((d - today) / 86400000);
}

// 임박도 음영 단계 (0=가장 임박)
function heatClass(iso) {
  const d = daysUntil(iso);
  if (d === null) return "";
  if (d < 0) return "heat-past";
  if (d <= 2) return "heat-0";
  if (d <= 7) return "heat-1";
  if (d <= 14) return "heat-2";
  return "";
}

// 최근기일 정렬값: 다가오는 기일(가까운 순) → 지난 기일(최근 순) → 미입력
function hearingSortValue(c) {
  const d = daysUntil(c.hearingDate);
  if (d === null) return 1e9;
  if (d >= 0) return d;
  return 1e6 + -d;
}

// 지난 공판 = 다음 기일 입력 필요
function needsHearingUpdate(c) {
  const d = daysUntil(c.hearingDate);
  return c.hearingType === "공판" && d !== null && d < 0;
}

// 지난 선고 = 항소 여부 확인 대상
function isPastVerdict(c) {
  const d = daysUntil(c.hearingDate);
  return c.hearingType === "선고" && d !== null && d < 0;
}
// 항소 여부 아직 미선택
function needsAppealCheck(c) {
  return isPastVerdict(c) && !c.appeal;
}

// 목록 우선순위: 확인 필요(맨 위) → 일반 → 보수청구 완료(맨 아래)
function caseRank(c) {
  if (c.claimed) return 2;
  if (needsHearingUpdate(c) || needsAppealCheck(c)) return 0;
  return 1;
}

