const COPY_RANGES = [
  "100장 이하",
  "101장 이상 ~ 200장 이하",
  "201장 이상 ~ 300장 이하",
  "301장 이상 ~ 400장 이하",
  "401장 이상 ~ 500장 이하",
  "500장 초과",
];

// 괄호 안 숫자 입력
function ParenNum({ value, onChange, wide }) {
  return (
    <input
      className={"gk-paren" + (wide ? " gk-paren-w" : "")}
      value={value}
      inputMode="numeric"
      onChange={(e) => onChange(e.target.value.replace(/[^0-9]/g, ""))}
    />
  );
}

// 문서용 체크박스 (□ / √)
function DocCheck({ checked, onClick }) {
  return (
    <button
      className={"gk-docchk" + (checked ? " on" : "")}
      onClick={onClick}
      aria-pressed={checked}
      aria-label="체크"
    >
      {checked ? "√" : ""}
    </button>
  );
}

