// ───────────────────────────────────────────────────────────
// 국선보수관리 — 보수청구/입금 정리 + 입금 문자 자동 인식
// ───────────────────────────────────────────────────────────

const FEE_COLUMNS = [
  { key: "defendant", label: "피고인", w: 96 },
  { key: "caseNumber", label: "사건번호", w: 168 },
  { key: "verdict", label: "선고기일", w: 144 },
  { key: "claim", label: "보수청구일", w: 130 },
  { key: "deposit", label: "보수입금일", w: 152 },
  { key: "amount", label: "입금액", w: 140, flex: true },
];

// 작성일/날짜 → "2026. 6. 17."
function formatFull(iso) {
  if (!iso) return "";
  const p = iso.split("-");
  if (p.length !== 3) return iso;
  return `${p[0]}. ${Number(p[1])}. ${Number(p[2])}.`;
}

const pad2 = (n) => String(Number(n)).padStart(2, "0");

// 한국 사건번호 접미사 (검찰 형제 포함)
const CASE_SUFFIX =
  "고단|고합|고정|고약|노|도|초[가-힣]?|구단|구합|가단|가합|가소|나|다|머|차|카|드단|드합|르|므|즈단|즈합|비|라|마|바|자|타|허|호|형제|전|보";

function parseDepositSMS(text) {
  if (!text) return [];
  const re = new RegExp("(\\d{4}\\s*(?:" + CASE_SUFFIX + ")\\s*제?\\s*\\d+)", "g");
  const found = [];
  let m;
  while ((m = re.exec(text)) !== null) {
    found.push({ cn: m[1], idx: m.index });
  }
  const out = [];
  for (let i = 0; i < found.length; i++) {
    const start = found[i].idx;
    const end = i + 1 < found.length ? found[i + 1].idx : text.length;
    const chunk = text.slice(start, end);
    out.push({
      caseNumber: found[i].cn.replace(/\s+/g, ""),
      amount: extractAmount(chunk),
      date: extractDate(chunk),
    });
  }
  return out;
}

function extractAmount(s) {
  const m = s.match(/([0-9]{1,3}(?:,[0-9]{3})+|[0-9]+)\s*원/);
  if (m) return Number(m[1].replace(/,/g, ""));
  return null;
}

function extractDate(s) {
  let m = s.match(/(20\d{2})[.\-/]\s*(\d{1,2})[.\-/]\s*(\d{1,2})/);
  if (m) return `${m[1]}-${pad2(m[2])}-${pad2(m[3])}`;
  m = s.match(/(\d{1,2})\s*월\s*(\d{1,2})\s*일/);
  if (m) return `${new Date().getFullYear()}-${pad2(m[1])}-${pad2(m[2])}`;
  return "";
}

function FeesView({ claimedCases, updateCase, applyDepositSMS }) {
  const [smsText, setSmsText] = useState("");
  const [result, setResult] = useState(null);

  const handleApply = () => {
    const res = applyDepositSMS(smsText);
    setResult(res);
    if (res.some((r) => r.ok)) setSmsText("");
  };

  return (
    <>
      {/* 입금 문자 붙여넣기 */}
      <div className="gk-paste">
        <div className="gk-paste-head">
          <span className="gk-paste-title">입금 문자 붙여넣기</span>
          <span className="gk-paste-hint">
            받은 문자를 붙여넣고 ‘자동 입력’을 누르면 사건번호로 매칭되어 입금일·입금액이 채워집니다
          </span>
        </div>
        <textarea
          className="gk-paste-area"
          value={smsText}
          onChange={(e) => setSmsText(e.target.value)}
          placeholder="예) [인천지방법원] 2022고단7948 국선변호 보수 350,000원이 입금되었습니다. (2026.6.17.)"
        />
        <div className="gk-paste-actions">
          {result && (
            <button className="gk-paste-clear" onClick={() => setResult(null)}>
              결과 지우기
            </button>
          )}
          <button
            className="gk-paste-btn"
            onClick={handleApply}
            disabled={!smsText.trim()}
          >
            자동 입력
          </button>
        </div>
        {result && <PasteResult result={result} />}
      </div>

      {/* 보수 정리 표 */}
      <div className="gk-card">
        <div className="gk-scroll">
          <div className="gk-table" role="table">
            <div className="gk-thead" role="row">
              {FEE_COLUMNS.map((col) => (
                <div
                  key={col.key}
                  role="columnheader"
                  className={"gk-th" + (col.flex ? " gk-flex" : "")}
                  style={col.flex ? { minWidth: col.w } : { width: col.w }}
                >
                  {col.label}
                </div>
              ))}
            </div>

            {claimedCases.length === 0 ? (
              <div className="gk-empty">
                <div className="gk-empty-icon">
                  <DocIcon />
                </div>
                <p className="gk-empty-title">보수청구 완료된 사건이 없습니다</p>
                <p className="gk-empty-sub">
                  사건 목록에서 ‘보수청구’로 신청서를 작성완료하면 여기에 표시됩니다
                </p>
              </div>
            ) : (
              claimedCases.map((c) => (
                <FeeRow key={c.id} c={c} updateCase={updateCase} />
              ))
            )}
          </div>
        </div>
      </div>
    </>
  );
}

function FeeRow({ c, updateCase }) {
  const form = c.feeForm || {};
  const verdict = c.verdictDate || (c.hearingType === "선고" ? c.hearingDate : "");
  const claimDate = form.writeDate || "";

  return (
    <div className="gk-row" role="row">
      <Cell w={96}>
        <span className="gk-fee-text gk-strong">{c.defendant || "—"}</span>
      </Cell>
      <Cell w={168}>
        <span className="gk-fee-text">{c.caseNumber || "—"}</span>
      </Cell>
      <Cell w={144}>
        <input
          type="date"
          className={"gk-fee-date" + (verdict ? " filled" : "")}
          value={verdict}
          onChange={(e) => updateCase(c.id, "verdictDate", e.target.value)}
        />
      </Cell>
      <Cell w={130}>
        <span className="gk-fee-text gk-fee-muted">
          {claimDate ? formatFull(claimDate) : "—"}
        </span>
      </Cell>
      <Cell w={152}>
        <input
          type="date"
          className={"gk-fee-date" + (c.depositDate ? " filled" : "")}
          value={c.depositDate || ""}
          onChange={(e) => updateCase(c.id, "depositDate", e.target.value)}
        />
      </Cell>
      <Cell flex minW={140}>
        <AmountInput
          value={c.depositAmount || ""}
          onChange={(v) => updateCase(c.id, "depositAmount", v)}
        />
      </Cell>
    </div>
  );
}

function AmountInput({ value, onChange }) {
  const display = value ? Number(value).toLocaleString("ko-KR") : "";
  return (
    <div className="gk-amt-wrap">
      <input
        className="gk-amt-input"
        inputMode="numeric"
        value={display}
        placeholder="0"
        onChange={(e) => onChange(e.target.value.replace(/[^0-9]/g, ""))}
      />
      <span className="gk-amt-won">원</span>
    </div>
  );
}

function PasteResult({ result }) {
  const ok = result.filter((r) => r.ok);
  const no = result.filter((r) => !r.ok);
  return (
    <div className="gk-paste-result">
      {ok.length > 0 && (
        <p className="gk-pr-ok">
          ✓ {ok.length}건 입력됨 —{" "}
          {ok
            .map(
              (r) =>
                `${r.defendant || r.caseNumber}${
                  r.amount != null ? ` ${r.amount.toLocaleString("ko-KR")}원` : ""
                }`
            )
            .join(", ")}
        </p>
      )}
      {no.length > 0 && (
        <p className="gk-pr-no">
          매칭 실패 {no.length}건: {no.map((r) => r.caseNumber).join(", ")} — 등록된
          사건번호와 일치하는지 확인하세요
        </p>
      )}
      {result.length === 0 && (
        <p className="gk-pr-no">문자에서 사건번호를 찾지 못했습니다. 형식을 확인해 주세요.</p>
      )}
    </div>
  );
}

function CloudSettings({ cloud, connected, status, syncTimes, onConnect, onSyncNow, onForcePull, onForcePush, onDisconnect, onClose }) {
  const [masterKey, setMasterKey] = useState(cloud.masterKey || "");
  const [binId, setBinId] = useState(cloud.binId || "");
  const [passphrase, setPassphrase] = useState(cloud.passphrase || "");
  const [code, setCode] = useState("");
  const [showGuide, setShowGuide] = useState(!connected);
  const [showAdvanced, setShowAdvanced] = useState(!!cloud.binId);
  const [copied, setCopied] = useState(false);

  const doConnect = () => onConnect({ masterKey, binId, passphrase });

  const exportCode = () => {
    try {
      const s = btoa(
        unescape(
          encodeURIComponent(
            JSON.stringify({ m: cloud.masterKey, b: cloud.binId, p: cloud.passphrase })
          )
        )
      );
      if (navigator.clipboard) navigator.clipboard.writeText(s);
      setCopied(true);
      setTimeout(() => setCopied(false), 1800);
    } catch (e) {}
  };
  const importCode = () => {
    try {
      const o = JSON.parse(decodeURIComponent(escape(atob(code.trim()))));
      setMasterKey(o.m || "");
      setBinId(o.b || "");
      setPassphrase(o.p || "");
      setShowAdvanced(true);
      onConnect({ masterKey: o.m, binId: o.b, passphrase: o.p });
    } catch (e) {
      alert("연결 코드를 읽을 수 없습니다. 다시 확인해 주세요.");
    }
  };

  return (
    <div className="gk-modal-backdrop" onClick={onClose}>
      <div className="gk-modal" onClick={(e) => e.stopPropagation()} role="dialog">
        <div className="gk-modal-head">
          <span className="gk-modal-title">클라우드 동기화</span>
          <button className="gk-modal-x" onClick={onClose} aria-label="닫기">
            ×
          </button>
        </div>
        <p className="gk-modal-sub">
          여러 PC에서 같은 사건 내역을 보도록 동기화합니다. 데이터는 아래 비밀번호로
          암호화되어 올라가며, 비밀번호를 아는 기기에서만 열립니다.
        </p>

        {(status.msg || status.lastSync) && (
          <div className={"gk-status " + status.state}>
            {status.state === "syncing"
              ? status.msg || "동기화 중…"
              : status.msg ||
                (status.state === "ok" ? "동기화됨" : "")}
            {status.lastSync ? (
              <span className="gk-status-time"> · 마지막 동기화 {formatSyncTime(status.lastSync)}</span>
            ) : null}
          </div>
        )}

        <div className="gk-field">
          <label>마스터 키 (X-Master-Key)</label>
          <input
            type="password"
            value={masterKey}
            onChange={(e) => setMasterKey(e.target.value)}
            placeholder="$2a$10$..."
            autoComplete="off"
          />
        </div>
        <div className="gk-field">
          <label>동기화 비밀번호 (암호화용)</label>
          <input
            type="password"
            value={passphrase}
            onChange={(e) => setPassphrase(e.target.value)}
            placeholder="다른 PC에서도 똑같이 입력"
            autoComplete="off"
          />
        </div>

        <button className="gk-toggle-link" onClick={() => setShowAdvanced((v) => !v)}>
          {showAdvanced ? "− 저장소 ID 숨기기" : "+ 저장소 ID 직접 입력 (다른 PC 연결 시)"}
        </button>
        {showAdvanced && (
          <div className="gk-field">
            <label>저장소 ID (Bin ID)</label>
            <input
              value={binId}
              onChange={(e) => setBinId(e.target.value)}
              placeholder="비워두면 새로 생성됩니다"
              autoComplete="off"
            />
          </div>
        )}

        <div className="gk-modal-actions">
          <button className="gk-btn-primary" onClick={doConnect}>
            {connected ? "다시 연결 / 동기화" : "연결 및 동기화"}
          </button>
          {connected && (
            <button className="gk-btn-ghost" onClick={onSyncNow}>
              지금 동기화
            </button>
          )}
        </div>

        {connected && (
          <>
            <div className="gk-sync-box">
              <div className="gk-sync-times">
                <span>
                  마지막 올림(이 PC):{" "}
                  <b>{syncTimes && syncTimes.push ? formatSyncTime(syncTimes.push) : "없음"}</b>
                </span>
                <span>
                  마지막 받음(이 PC):{" "}
                  <b>{syncTimes && syncTimes.pull ? formatSyncTime(syncTimes.pull) : "없음"}</b>
                </span>
              </div>
              <p className="gk-sync-hint">
                다른 PC 내용이 안 보이면 ‘서버에서 받아오기’, 이 PC 내용을 서버에 확실히 올리려면
                ‘서버로 올리기’를 누르세요. 시각 비교 없이 한쪽을 그대로 덮어씁니다.
              </p>
              <div className="gk-modal-actions">
                <button
                  className="gk-btn-ghost"
                  onClick={() => {
                    if (
                      confirm(
                        "서버에 저장된 내용으로 이 PC를 덮어씁니다. 계속할까요?\n(이 PC의 저장 안 된 변경은 사라질 수 있습니다.)"
                      )
                    )
                      onForcePull && onForcePull();
                  }}
                >
                  ⬇ 서버에서 받아오기
                </button>
                <button
                  className="gk-btn-ghost"
                  onClick={() => {
                    if (
                      confirm(
                        "이 PC의 내용으로 서버를 덮어씁니다. 계속할까요?\n(다른 PC에서 올린 더 최신 내용이 있으면 사라질 수 있습니다.)"
                      )
                    )
                      onForcePush && onForcePush();
                  }}
                >
                  ⬆ 서버로 올리기
                </button>
              </div>
            </div>

            <div className="gk-modal-actions" style={{ marginTop: 10 }}>
              <button className="gk-btn-ghost" onClick={exportCode}>
                {copied ? "복사됨 ✓" : "다른 PC용 연결 코드 복사"}
              </button>
              <button className="gk-btn-danger" onClick={onDisconnect}>
                연결 해제
              </button>
            </div>
            <p className="gk-guide-warn" style={{ marginTop: 6 }}>
              연결 코드에는 키와 비밀번호가 모두 담겨 있으니 외부에 노출되지 않게 보관하세요.
            </p>
          </>
        )}

        <div className="gk-field" style={{ marginTop: 14 }}>
          <label>다른 PC에서 연결 코드로 한 번에 연결</label>
          <div className="gk-code-row">
            <input
              value={code}
              onChange={(e) => setCode(e.target.value)}
              placeholder="연결 코드 붙여넣기"
              autoComplete="off"
            />
            <button className="gk-btn-ghost" onClick={importCode} disabled={!code.trim()}>
              코드로 연결
            </button>
          </div>
        </div>

        <button className="gk-toggle-link" onClick={() => setShowGuide((v) => !v)}>
          {showGuide ? "− 처음 설정 방법 접기" : "＋ 처음 설정 방법 보기"}
        </button>
        {showGuide && (
          <div className="gk-guide">
            <p className="gk-guide-t">처음 한 번만 (약 3분)</p>
            <ol>
              <li>jsonbin.io 에 접속해 무료 가입 후 로그인</li>
              <li>로그인 후 ‘API Keys’ 메뉴에서 X-Master-Key를 복사</li>
              <li>위 ‘마스터 키’ 칸에 붙여넣기</li>
              <li>‘동기화 비밀번호’를 정해서 입력 (꼭 기억해 두세요)</li>
              <li>‘연결 및 동기화’ 클릭 → 저장소가 자동 생성됩니다</li>
              <li>
                다른 PC에서는 이 PC의 ‘연결 코드 복사’로 받은 코드를 붙여넣고 ‘코드로 연결’만 누르면
                끝
              </li>
            </ol>
            <p className="gk-guide-warn">
              ⚠ 동기화 비밀번호를 잊으면 클라우드의 데이터를 복구할 수 없습니다. · 로컬 파일에서
              연결이 안 되면, 파일을 인터넷에 올려(호스팅) 주소로 열면 안정적으로 동작합니다.
            </p>
          </div>
        )}
      </div>
    </div>
  );
}

function ImportModal({ state, onChange, onConfirm, onRetry, onClose }) {
  const { phase, msg, data, error } = state;
  return (
    <div className="gk-modal-backdrop" onClick={phase === "loading" ? undefined : onClose}>
      <div className="gk-modal" onClick={(e) => e.stopPropagation()} role="dialog">
        <div className="gk-modal-head">
          <span className="gk-modal-title">공소장에서 자동 입력</span>
          {phase !== "loading" && (
            <button className="gk-modal-x" onClick={onClose} aria-label="닫기">
              ×
            </button>
          )}
        </div>

        {phase === "loading" && (
          <div className="gk-imp-loading">
            <div className="gk-spinner" />
            <p>{msg || "읽는 중…"}</p>
            <p className="gk-imp-hint">문서는 이 컴퓨터 안에서만 처리되며 외부로 전송되지 않습니다.</p>
          </div>
        )}

        {phase === "error" && (
          <>
            <div className="gk-status error">{error}</div>
            <p className="gk-modal-sub">
              전자(글자) PDF가 아니거나 인식에 실패했을 수 있습니다. 다른 파일로 다시 시도하거나, 직접
              입력해 주세요.
            </p>
            <div className="gk-modal-actions">
              <button className="gk-btn-primary" onClick={onRetry}>
                다시 업로드
              </button>
              <button className="gk-btn-ghost" onClick={onClose}>
                닫기
              </button>
            </div>
          </>
        )}

        {phase === "review" && (
          <>
            <p className="gk-modal-sub">
              추출된 내용을 확인·수정한 뒤 추가하세요. 빈 칸은 공소장에서 찾지 못한 항목이니 직접
              입력하시면 됩니다.
            </p>
            <div className="gk-field">
              <label>피고인</label>
              <input value={data.defendant} onChange={(e) => onChange("defendant", e.target.value)} />
            </div>
            <div className="gk-field">
              <label>연락처</label>
              <input
                value={data.contact}
                placeholder="공소장에 없으면 직접 입력"
                onChange={(e) => onChange("contact", e.target.value)}
              />
            </div>
            <div className="gk-field">
              <label>사건번호</label>
              <input value={data.caseNumber} onChange={(e) => onChange("caseNumber", e.target.value)} />
            </div>
            <div className="gk-field">
              <label>사건명 (죄명)</label>
              <input value={data.caseName} onChange={(e) => onChange("caseName", e.target.value)} />
            </div>
            <div className="gk-modal-actions">
              <button className="gk-btn-primary" onClick={onConfirm}>
                사건 추가
              </button>
              <button className="gk-btn-ghost" onClick={onClose}>
                취소
              </button>
            </div>
          </>
        )}
      </div>
    </div>
  );
}

